import java.io.*;

public class CommandInjectionSecure {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        System.out.print("Enter the file name to display: ");
        String fileName = reader.readLine();

        // Secure code - using ProcessBuilder with proper argument passing
        ProcessBuilder processBuilder = new ProcessBuilder("cat", fileName);
        processBuilder.redirectErrorStream(true);

        Process process = processBuilder.start();

        try (BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
            String line;
            while ((line = inputReader.readLine()) != null) {
                System.out.println(line);
            }
        }
    }
}

### Explanation:
취약유형: Command Injection
